async (params, browser) => {
  // Open hashtag page
  await browser.open(`https://www.tiktok.com/tag/${params.hashtag}`)

  // Wait for hashtag page to load
  await browser.waitForSelector('[data-e2e="challenge-item"], [data-e2e="challenge-vcard"], div[class*="DivVideoCard"]', 15000)

  // Let page fully render
  await browser.wait(3000)

  // Scroll to load more videos
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Scroll for additional content
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract hashtag info and top videos
  const hashtag_data = await browser.evaluate(`const viewCountEl = document.querySelector('[data-e2e="challenge-vcount"], [data-e2e="challenge-view-count"], strong[class*="StrongNumber"], h2[class*="H2ShareSubTitle"]'); const descEl = document.querySelector('[data-e2e="challenge-desc"], p[class*="PDesc"], .challenge-description'); const videos = []; const items = document.querySelectorAll('[data-e2e="challenge-item"], [data-e2e="challenge-vcard"], div[class*="DivVideoCardBody"], div[class*="DivWrapper"] > div[class*="DivVideoCard"]'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const descItemEl = el.querySelector('[data-e2e="challenge-item-desc"], a[title], .card-desc'); const creatorEl = el.querySelector('[data-e2e="challenge-item-username"], [data-e2e="creator-uniqueid"], .author-uniqueid, p[class*="PAuthorTitle"]'); const viewsEl = el.querySelector('[data-e2e="video-views"], strong.video-count, .view-count, span[class*="SpanCount"]'); const thumbEl = el.querySelector('img[src*="tiktokcdn"], img.poster, picture img'); const linkEl = el.querySelector('a[href*="/video/"], a[href*="/@"]'); videos.push({ description: descItemEl ? (descItemEl.getAttribute('title') || descItemEl.textContent.trim()).substring(0, 300) : '', creator: creatorEl ? creatorEl.textContent.trim() : '', views: viewsEl ? viewsEl.textContent.trim() : '', thumbnail: thumbEl ? thumbEl.src : '', url: linkEl ? linkEl.href : '' }); } return { hashtag: '' + params.hashtag + '', total_views: viewCountEl ? viewCountEl.textContent.trim() : '', description: descEl ? descEl.textContent.trim().substring(0, 500) : '', video_count: videos.length, top_videos: videos }`)

  return hashtag_data
}
